INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Course authoring$q$, $q$Build structured courses and learning paths with multimedia lessons, quizzes, and configurable exam types.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$SCORM & xAPI support$q$, $q$Import and export standards-compliant e-learning content, enabling interoperability with other LMS platforms and authoring tools.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Virtual classrooms$q$, $q$Integrated video conferencing for live, real-time teaching sessions alongside self-paced content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Built-in social learning$q$, $q$Forums, chat, and wiki pages embedded in each course to support discussion and collaboration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Certificates & skills tracking$q$, $q$Automatically generate completion certificates and track learner competencies across courses.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Course catalog & shopping cart$q$, $q$Publish a public course catalog and sell course access directly through the platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$AI-assisted content and grading$q$, $q$AI tooling to help generate course content and support automated assessment grading.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Free and open-source with no per-user licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Certified Digital Public Good with a large global user base$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Broad feature set covering authoring, assessment, video conferencing, and social learning in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Full control over data and hosting since it is self-hosted$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Requires self-hosting, so organizations need server infrastructure and technical maintenance capacity$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Chamilo PRO enterprise support pricing is not publicly listed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Interface and workflows can feel dated compared to newer commercial LMS products$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Smaller commercial ecosystem and marketplace than larger LMS platforms like Moodle$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Is Chamilo LMS free?$q$, $q$Yes, the core Chamilo LMS software is free and open-source. Optional paid enterprise services (Chamilo PRO) cover hosting, support, and maintenance for organizations that don't want to self-manage the platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Who develops Chamilo?$q$, $q$Chamilo is maintained by the nonprofit Chamilo Association, founded in Belgium in 2010, with development and enterprise services led by BeezNest since January 2026.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Does Chamilo support SCORM and xAPI content?$q$, $q$Yes, Chamilo supports both SCORM and xAPI (Tin Can) standards for importing and exporting e-learning content.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$How is Chamilo different from Moodle?$q$, $q$Both are open-source LMS platforms, but Chamilo positions itself as a lighter-weight, simpler-to-deploy alternative to Moodle, with built-in social tools and a course marketplace feature.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Can I sell courses through Chamilo?$q$, $q$Yes, Chamilo includes a course catalog with shopping-cart functionality so institutions can publish and sell course access.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Higher education and school course delivery$q$, $q$Universities and schools use Chamilo to host blended and fully online courses with assessments, certificates, and virtual classrooms.$q$, $q$Educational institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Corporate training programs$q$, $q$Companies deploy Chamilo to deliver compliance training, onboarding, and skills development while tracking completion and competencies.$q$, $q$Enterprise L&D teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Paid course marketplaces$q$, $q$Training providers use the built-in catalog and shopping cart to sell access to courses directly to learners.$q$, $q$Independent training providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Community (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source LMS software","Self-hosted on your own server","Course authoring, assessments, and certificates","SCORM/xAPI support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$Chamilo PRO$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Managed hosting","Priority technical support","Maintenance and upgrades","Migration and integration services","Consulting"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chamilo LMS is an open-source learning management system built for schools, universities, training organizations, and corporate learning teams that want to run online courses without paying per-seat SaaS fees. The project descends from the Claroline and Dokeos e-learning platforms and was established under its current name in 2010 by the nonprofit Chamilo Association, registered in Belgium and headquartered in Spain since 2014.$q$, $q$The platform is free to download, self-host, and modify under its open-source license, and it has been recognized as a Digital Public Good by the UN-backed Digital Public Goods Alliance. Chamilo reports usage by tens of millions of learners globally, spanning public education systems, NGOs, and enterprise training departments.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Chamilo covers course creation and delivery end-to-end: authoring tools for lessons and learning paths, configurable exams and assessments, SCORM and xAPI compliance for importing and exporting standards-based content, certificate generation, and skills/competency tracking tied to course completion.$q$, $q$Social and collaborative features — forums, real-time chat, and wikis — are built into every course space, and integrated video conferencing supports live virtual classroom sessions. A course catalog with shopping-cart functionality lets institutions sell courses directly, and recent versions have added AI-assisted tools for content generation and grading.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Chamilo LMS software is free open-source software with no license cost; organizations can download and self-host it on their own infrastructure indefinitely. Real-world total cost of ownership comes from server hosting, IT administration, and any custom plugin development an organization takes on itself.$q$, $q$For organizations that prefer not to manage hosting and maintenance internally, Chamilo PRO is a paid enterprise services offering that bundles managed hosting, technical support, upgrades, migrations (including from Moodle), integrations, and consulting. Chamilo PRO pricing is quoted individually and is not published publicly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e674cd08-a074-41e5-a462-469391a5b739', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Selective element monitoring$q$, $q$Choose exactly which part of a page to watch using a visual selector, CSS/XPath, or regex, avoiding noise from unrelated page changes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Price & restock detection$q$, $q$Set upper/lower price thresholds and get alerted when out-of-stock products become available again.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Browser automation steps$q$, $q$Automate logins, cookie dismissals, cart additions, and searches before a watch captures its target content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$PDF change tracking$q$, $q$Detect updates to PDF documents via filesize and checksum comparison without manual re-downloading.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Multi-channel notifications$q$, $q$Send alerts via Discord, Slack, Telegram, email, Office 365, ntfy, Matrix, Rocket.Chat, and custom webhooks through the Apprise library.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Self-hosted deployment$q$, $q$Run via Docker, pip, or source with no artificial limits on the number of watched URLs beyond your own infrastructure.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Free and fully open-source with no forced limits when self-hosted$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Highly flexible element selection and filtering for precise alerts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Wide range of built-in notification integrations via Apprise$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Active open-source development community$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Self-hosting requires basic technical setup (Docker or Python environment)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$High-frequency or large-scale monitoring is easier via the paid cloud plan rather than self-hosting$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Interface is functional rather than highly polished$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$No official enterprise support tier for self-hosted deployments$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Is changedetection.io free?$q$, $q$Yes, the self-hosted open-source version is completely free. A paid cloud-hosted plan starting at $8.99/month is available for users who don't want to manage their own server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$How do I self-host changedetection.io?$q$, $q$It can be run via a Docker container, installed with pip, or run from source, and is available on GitHub under the maintainer dgtlmoon.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Can changedetection.io track prices and restocks?$q$, $q$Yes, it has dedicated logic for price-change thresholds and for alerting when an out-of-stock product becomes available again.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$What notification services does it support?$q$, $q$Through the Apprise library it supports Discord, Slack, Telegram, email, Office 365, ntfy, Matrix, Rocket.Chat, and custom webhooks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Does it work on pages that require login or interaction?$q$, $q$Yes, browser automation steps let a watch log in, click through pages, or add items to a cart before capturing the content to monitor.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$E-commerce price and restock tracking$q$, $q$Shoppers and resellers monitor product pages for price drops and back-in-stock alerts on limited or high-demand items.$q$, $q$Online shoppers and resellers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Competitive and content monitoring$q$, $q$Businesses track competitor websites, pricing pages, or portfolio content for changes relevant to their market.$q$, $q$Marketing and competitive intelligence teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Legal and policy document tracking$q$, $q$Organizations monitor terms of service, regulatory filings, or policy PDFs for updates without manual re-checking.$q$, $q$Legal and compliance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source software","Unlimited watches (limited by your own infrastructure)","All core monitoring and notification features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$Cloud$q$, $q$$8.99/month$q$, $q$monthly$q$, NULL, $q$["Up to 5,000 monitored URLs","Checks as frequent as every 5 minutes","No self-hosting required"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$changedetection.io is a free, open-source website change monitoring tool that alerts users whenever a tracked web page's content, price, or availability changes. It is designed to be self-hosted, most commonly via Docker, and is developed in the open on GitHub under maintainer dgtlmoon, with an optional paid cloud-hosted version for users who don't want to manage their own infrastructure.$q$, $q$Typical uses include catching e-commerce price drops, getting notified when an out-of-stock item comes back in stock, tracking changes to legal or policy documents, and monitoring competitor or portfolio websites for updates.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can select specific elements to monitor on a page — via a visual selector, CSS/XPath selectors, or LXML regex functions — so alerts fire only on meaningful changes rather than every minor page update. Dedicated price and stock-detection logic supports configurable price thresholds and back-in-stock alerts.$q$, $q$Built-in browser automation lets watches perform steps like logging in, accepting cookie banners, or adding an item to a cart before capturing content. The tool can also track PDF file changes via filesize and checksum comparison, and it sends notifications through the Apprise library to destinations including Discord, Slack, Telegram, email, ntfy, Matrix, Rocket.Chat, and custom webhooks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$changedetection.io is free to self-host indefinitely; the only cost is the infrastructure a user runs it on. For users who prefer not to manage hosting, a cloud-hosted SaaS plan is available starting at $8.99 per month, supporting up to 5,000 monitored URLs with checks as frequent as every 5 minutes.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Unified chat and task management$q$, $q$Convert any chat message into a task with one click, then assign, prioritize, and track it without leaving the conversation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Large-scale video calls$q$, $q$Host video meetings with up to 1,000 participants and up to 49 visible video tiles at 4K quality.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Unlimited searchable history$q$, $q$Full-text search across all conversations, included even on the free plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Third-party integrations$q$, $q$Connect with Zapier, Google Drive, GitHub, Dropbox, Asana, and other tools teams already use.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Security & compliance options$q$, $q$HIPAA compliance, SSO, and two-factor authentication available on the Business plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Guest access$q$, $q$Business plan includes free guest seats per member for collaborating with external partners or clients.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Generous free plan with unlimited message history for up to 5 users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Affordable per-user pricing compared to Slack and Microsoft Teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Built-in task management removes need for a separate project tool for lightweight use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$HIPAA compliance and SSO available at the standard Business tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Free plan is capped at 5 team members$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Enterprise pricing is not publicly listed$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Smaller third-party app ecosystem than Slack$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Advanced admin controls (directory sync, SCIM) require the custom Enterprise plan$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Is Chanty free?$q$, $q$Yes, Chanty has a free-forever plan for up to 5 team members with unlimited chat history and 20GB of storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$How much does Chanty's Business plan cost?$q$, $q$The Business plan costs $3 per user per month billed annually, or $4 per user per month billed monthly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Does Chanty include task management?$q$, $q$Yes, any chat message can be converted into a task with a single click, and tasks can be assigned, prioritized, and tracked within the app.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Does Chanty support video calls?$q$, $q$Yes, Chanty supports video conferencing with up to 1,000 participants and up to 49 visible video tiles at 4K quality.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Is Chanty HIPAA compliant?$q$, $q$HIPAA compliance is included on the Business plan and higher.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Small business team communication$q$, $q$Small teams use Chanty's free or low-cost Business plan as an affordable Slack alternative for daily communication.$q$, $q$Small businesses and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Lightweight project coordination$q$, $q$Teams convert chat messages directly into assigned, trackable tasks without adopting a separate project management tool.$q$, $q$Operations and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Compliance-sensitive collaboration$q$, $q$Healthcare-adjacent or security-conscious teams use Business-tier HIPAA compliance and SSO/2FA for protected communication.$q$, $q$Healthcare and security-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Free$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["Up to 5 team members","Unlimited chats and searchable history","One-on-one voice calls","Task management","20GB file storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Business$q$, $q$$3/user/month (annual) or $4/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited team members","Unlimited group voice/video calls","Screen sharing","Employee directory & calendar","HIPAA compliance, SSO, 2FA","3 free guest seats per member"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["White-labeling","Directory sync & SCIM provisioning","Usage analytics","Unlimited integrations","On-premise options","Dedicated account management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chanty is a team chat and collaboration app founded in 2017 and based in New York. It positions itself as a faster, simpler, and lower-cost alternative to Slack and Microsoft Teams, built around messaging, voice/video calls, and built-in task management in a single interface.$q$, $q$The product is aimed at small businesses, mid-market teams, and enterprise groups that want core team communication features — chat, calls, and lightweight task tracking — without the cost or complexity of larger enterprise collaboration suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Chanty supports unlimited public and private conversations with searchable history, one-on-one and group voice/video calls (up to 1,000 participants and 49 visible video tiles), and screen sharing. Any message can be turned into a task with one click, and tasks can be assigned, prioritized, and tracked without a separate project management tool.$q$, $q$The platform integrates with Zapier, Google Drive, GitHub, Dropbox, and Asana, among others. Higher tiers add an employee directory, shared calendar, polls and forms, HIPAA compliance, SSO, and two-factor authentication for teams with stricter security or compliance needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Chanty's Free plan supports up to 5 team members with unlimited chat history and 20GB of file storage. The Business plan costs $3/user/month billed annually (or $4/user/month billed monthly) and removes the team-size cap while adding screen sharing, HIPAA compliance, SSO/2FA, and more.$q$, $q$An Enterprise plan with custom pricing adds white-labeling, directory sync, SCIM provisioning, and on-premise deployment options. Chanty offers a 50% discount for nonprofits and education, plus a 14-day money-back guarantee on paid plans.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d9e0aeb4-501a-4642-a40a-1a439d823b46', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
