INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Live chat widget$q$, $q$Real-time chat with website visitors, customizable to match brand appearance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Multi-channel inbox$q$, $q$Consolidate messages from Facebook, Viber, Telegram, and email alongside live chat in one place.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Chatbots & FAQ bot$q$, $q$Automate answers to common questions and deflect repetitive tickets before they reach an agent.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Auto-invitations$q$, $q$Trigger proactive chat messages based on visitor behavior to start conversations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Knowledge base$q$, $q$Self-service help content customers can search before starting a chat.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Saved replies & pre-chat forms$q$, $q$Speed up agent responses and collect visitor information before a conversation begins.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Reporting$q$, $q$Standard and on-demand reports on chat volume, response times, and agent performance.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Usable free plan with 2 operators and unlimited chats/websites$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Multi-channel messaging including Viber and Telegram, less common among competitors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Affordable Pro tier compared to larger customer service suites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Available on web, desktop, and mobile$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Free plan chat history limited to 60 days$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Advanced automation (chatbots, knowledge base) only available on the top Unlimited plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Native integrations are limited mainly to Zapier rather than a broad app marketplace$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Not a full helpdesk/ticketing platform, so may need pairing with another tool for complex support operations$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Is Chaport free?$q$, $q$Yes, Chaport has a free plan with 2 operator seats, unlimited chats and websites, and 60 days of chat history.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$How much does Chaport cost?$q$, $q$Paid plans start at $29/month for Pro (4 operators) and $99/month for Unlimited (unlimited operators), both billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Does Chaport support Facebook and Telegram messaging?$q$, $q$Yes, Chaport consolidates Facebook Messenger, Viber, Telegram, and email alongside live chat in one inbox.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Does Chaport have chatbots?$q$, $q$Yes, chatbots and a knowledge base/FAQ bot are included on the Unlimited plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Is there a free trial?$q$, $q$Yes, paid plans include a 14-day free trial with no credit card required.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Small business customer support$q$, $q$Small teams use Chaport's Free or Pro plan as an affordable way to add live chat and messaging support to their website.$q$, $q$Small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$E-commerce sales chat$q$, $q$Online stores use auto-invitations and multi-channel messaging to engage shoppers and answer pre-sale questions in real time.$q$, $q$E-commerce businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Agency management of multiple client sites$q$, $q$Agencies use Chaport across multiple websites under one account to manage chat support for several clients.$q$, $q$Digital agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Free$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["2 operators","Unlimited chats and websites","60-day chat history","Basic widget customization","Web, desktop, and mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Pro$q$, $q$$29/month (billed annually)$q$, $q$annual$q$, NULL, $q$["4 operators","Unlimited chat history","Auto-invitations","Facebook, Viber, Telegram integration","Saved replies & pre-chat forms","Detailed reports"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$Unlimited$q$, $q$$99/month (billed annually)$q$, $q$annual$q$, NULL, $q$["Unlimited operators","Chatbots & knowledge base","Teams & assignment rules","Custom fields & chat ratings","Advanced & on-demand reports","Zapier integration"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chaport is a live chat and customer messaging platform founded in 2014 and based in Alhambra, California. It lets businesses chat with website visitors in real time while also consolidating messages from Facebook, Viber, Telegram, and email into one inbox, and it adds chatbots and a knowledge base to automate common support questions.$q$, $q$The platform is used by more than 30,000 teams according to the company, with a focus on small and mid-sized businesses that want an affordable, quick-to-set-up alternative to larger customer service suites.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include the live chat widget, multi-channel messaging (Facebook, Viber, Telegram, email), auto-invitations that proactively message visitors, offline messaging, group chat, and agent-to-agent chat transfers. Chatbots and a knowledge base/FAQ bot let businesses automate responses to repetitive questions.$q$, $q$Additional tools include saved replies, pre-chat forms, chat ratings, and both standard and on-demand reporting. Chaport is available as a web app, desktop apps, and mobile apps, and it integrates with Zapier on the top-tier plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Chaport's Free plan includes 2 operator seats, unlimited chats and websites, and 60 days of chat history. The Pro plan starts at $29/month (annual billing) with 4 operators and unlimited history, while the Unlimited plan starts at $99/month (annual billing) with unlimited operators, chatbots, and the knowledge base.$q$, $q$Annual billing offers roughly a 25% discount over monthly pricing, and all paid plans include a 14-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('02537e9f-5e3e-4e2f-9b7e-a73669114bd6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
