INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Recurring billing & invoicing$q$, $q$Automate subscription creation, recurring invoices, and billing cycles across pricing models.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Smart dunning$q$, $q$Automated retry logic and customer communication workflows to recover failed recurring payments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$35+ payment gateway integrations$q$, $q$Connect to major payment processors including Stripe and PayPal to support customers across regions and currencies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Usage-based & hybrid billing$q$, $q$Combine flat subscription fees with metered, consumption-based charges, including monetization tooling for AI/usage products.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Hosted checkout & customer portal$q$, $q$Self-serve pages for signup and billing management, with custom domain support on higher tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Multi-entity billing$q$, $q$Manage billing across subsidiaries or business units with account hierarchy on the Enterprise plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$API & webhooks$q$, $q$Full API access for building custom billing logic and syncing billing events to other systems.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Free Starter tier accessible to early-stage startups up to $250K in lifetime billing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Strong dunning and failed-payment recovery tooling$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Broad payment gateway coverage (35+) for global businesses$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Scales from free tier to enterprise multi-entity billing on one platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Overage fees (0.75%) apply once billing volume exceeds each plan's threshold$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Performance plan requires an annual commitment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Enterprise pricing is not publicly listed and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Feature depth and configuration options can create a learning curve for new users$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Is Chargebee free?$q$, $q$The Starter plan is free for businesses with up to $250,000 in cumulative lifetime billing processed through Chargebee; a 0.75% overage fee applies beyond that.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$How much does Chargebee's Performance plan cost?$q$, $q$The Performance plan costs $599 per month, billed with an annual commitment (roughly $7,188/year), and covers up to $100,000 in monthly recurring revenue.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Does Chargebee support usage-based billing?$q$, $q$Yes, Chargebee supports usage-based and hybrid billing models that combine flat subscription fees with metered charges.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Does Chargebee integrate with Stripe and PayPal?$q$, $q$Yes, Chargebee integrates with more than 35 payment gateways, including major processors like Stripe and PayPal.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$What is included in Chargebee Enterprise?$q$, $q$Enterprise adds multi-entity billing, account hierarchy management, and custom negotiated contract terms, with pricing quoted individually.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Early-stage SaaS billing$q$, $q$Startups use the free Starter plan to launch subscription billing without upfront licensing costs.$q$, $q$Early-stage SaaS startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Scaling subscription businesses$q$, $q$Growing companies use the Performance plan's dunning and multi-gateway support to reduce churn and expand internationally.$q$, $q$Scaling subscription companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Multi-entity enterprise billing$q$, $q$Large organizations with multiple business units use Enterprise-tier account hierarchy and custom contracts to manage complex billing structures.$q$, $q$Enterprises with multiple business entities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Starter$q$, $q$Free (up to $250K lifetime billing)$q$, $q$N/A$q$, NULL, $q$["Recurring billing & invoicing","Hosted checkout & customer portal","Coupon management","Basic gateway integrations","0.75% overage above $250K"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Performance$q$, $q$$599/month$q$, $q$annual commitment$q$, NULL, $q$["Up to $100K MRR","Smart dunning","Consolidated invoicing","Custom domain checkout","Multiple gateway integrations","0.75% overage above threshold"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Multi-entity billing","Account hierarchy","Custom contracts","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chargebee is a subscription billing and revenue management platform founded in 2011 in Chennai, India, now with dual headquarters in San Francisco and Chennai. It automates recurring billing operations — invoicing, payments, dunning, and revenue reporting — for more than 6,500 subscription and SaaS businesses.$q$, $q$The platform is built to remove the operational overhead of running recurring billing manually, handling everything from checkout and payment collection to failed-payment recovery and usage-based monetization for companies with metered or consumption pricing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Chargebee supports recurring, usage-based, and hybrid billing models, hosted checkout pages and a self-serve customer portal, coupon and discount management, and integrations with more than 35 payment gateways. Smart dunning automates retrying and communicating around failed payments to reduce involuntary churn.$q$, $q$For larger organizations, Chargebee adds multi-entity billing and account hierarchy management, consolidated invoicing, and custom-domain checkout pages, along with a full API for teams building custom billing workflows on top of the platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Starter plan is free for up to $250,000 in cumulative lifetime billing, after which a 0.75% overage fee applies. The Performance plan costs $599/month (annual commitment) and covers up to $100,000 in monthly recurring revenue with the same overage rate beyond that.$q$, $q$The Enterprise plan is custom-priced and adds multi-entity billing, account hierarchy, and negotiated contract terms for larger organizations with complex billing structures.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('59e7c6f4-7f3f-4a9d-a078-a2b7d95263db', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
