INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Onboarding workflows$q$, $q$Automated, customizable onboarding checklists to get new hires set up quickly.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Absence & time-off management$q$, $q$Configurable leave types, manager approvals, and real-time calendar sync with Google or Outlook.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Centralized employee records$q$, $q$GDPR-compliant storage for employee data and HR documents in one system.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Self-serve employee portal$q$, $q$Employees can request time off and check allowance usage without emailing HR.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Automated reminders$q$, $q$Notifications for key HR deadlines and recurring administrative tasks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Charlie Recruit (add-on)$q$, $q$Applicant tracking system for managing hiring pipelines without separate recruitment software.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Charlie Advice (add-on)$q$, $q$1-to-1 HR advisory service for expert guidance on employment law and HR decisions.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Pricing scaled to small-company headcount rather than flat enterprise fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Strong onboarding and absence-management tools purpose-built for small teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Optional Recruit add-on avoids need for separate applicant tracking software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$UK-specific GDPR and employment law focus$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Pricing increases with headcount, so cost grows as the company scales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Recruit and Advice add-ons require an active Core subscription and can't be purchased standalone$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Primarily UK-oriented, less suited to non-UK companies$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$No full payroll processing built into the platform$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$How much does CharlieHR cost?$q$, $q$The Core HR plan starts at £20/month for businesses with 1–4 employees, scaling up to £735/month for 250+ employees, with a 75% introductory discount for new small customers in their first six months.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Is there a free trial for CharlieHR?$q$, $q$Yes, CharlieHR offers a 7-day free trial of the Core plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Does CharlieHR include payroll?$q$, $q$No, CharlieHR does not include full payroll processing; it focuses on onboarding, absence management, and employee records.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$What is Charlie Recruit?$q$, $q$Charlie Recruit is an optional add-on applicant tracking system that lets small teams manage hiring pipelines without separate recruitment software.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Who is CharlieHR built for?$q$, $q$CharlieHR is built for UK-based small businesses and startups that need lightweight HR admin tools but don't require an enterprise HRIS.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Small business HR administration$q$, $q$UK small businesses use CharlieHR to replace spreadsheets for onboarding, absence tracking, and employee records.$q$, $q$UK small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Startup hiring without a dedicated ATS$q$, $q$Startups use the Charlie Recruit add-on to manage hiring pipelines directly alongside their core HR data.$q$, $q$Startups and growing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Expert HR guidance for non-specialist teams$q$, $q$Businesses without an in-house HR expert use Charlie Advice for 1-to-1 employment law and HR decision support.$q$, $q$Small businesses without dedicated HR staff$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Core HR$q$, $q$From £20/month (1-4 employees, scaling to £735/month for 250+)$q$, $q$monthly$q$, NULL, $q$["Onboarding workflows","Absence management","GDPR-compliant employee records","Calendar sync","7-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Recruit (add-on)$q$, $q$From £55/month$q$, $q$monthly$q$, NULL, $q$["Applicant tracking","Hiring pipeline management","Requires active Core subscription"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$Advice (add-on)$q$, $q$From £179/month$q$, $q$monthly$q$, NULL, $q$["1-to-1 HR advisory","Employment law guidance","Requires active Core subscription"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CharlieHR is an HR software platform built for small businesses, founded in London in 2015 and still headquartered there today with a team of around 40 people across the UK. The product is designed to replace spreadsheets and manual processes for small-company HR admin, centered on onboarding, absence management, and employee records.$q$, $q$CharlieHR targets UK-based small businesses and startups that have outgrown manual HR tracking but are too small for an enterprise HRIS. Optional add-ons extend the core platform into recruitment and HR advisory services.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core platform includes GDPR-compliant employee records and document storage, smart onboarding workflows for new hires, and absence/time-off management with configurable leave types, manager approvals, and calendar sync to Google or Outlook. Employees can self-serve time-off requests and check their own allowance balances.$q$, $q$The Charlie Recruit add-on brings applicant tracking to manage hiring pipelines, and the Charlie Advice add-on connects businesses with 1-to-1 HR expertise for employment law and HR decisions — both requiring an active Core subscription.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CharlieHR's Core HR plan is priced by company headcount, starting at £20/month for 1–4 employees and scaling to £735/month for 250+ employees, with a 75% introductory discount for the first six months for new small customers (as low as £5/month initially).$q$, $q$Recruit starts from £55/month and Advice starts from £179/month, both requiring an active Core subscription; all prices exclude UK VAT. A 7-day free trial is available for the Core plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('28db2214-8104-44f7-8d16-5482ac920f21', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Multi-source data connections$q$, $q$Connect directly to PostgreSQL, MySQL, MongoDB databases and SaaS APIs like Stripe, Google Analytics, and Mailchimp.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Point-and-click & SQL query builder$q$, $q$Build queries visually or write raw SQL for full control over the underlying data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$AI-assisted query suggestions$q$, $q$AI tooling helps write and optimize SQL and MongoDB queries within the dashboard editor.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Scheduled reports & alerts$q$, $q$Automatically refresh dashboards, send snapshot reports, or trigger alerts via Slack, email, or webhooks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Embeddable dashboards$q$, $q$Embed individual charts or full dashboards into external websites or client portals.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Self-hosted or cloud deployment$q$, $q$Run Chartbrew free on your own infrastructure via Docker, or use the managed cloud version.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Free and open-source with full self-hosting option for data control$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Connects to relational databases, NoSQL, and SaaS APIs without a separate data layer$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Affordable cloud pricing for small teams and agencies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Embeddable dashboards suited to client-facing reporting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Free cloud tier limited to 3 team members$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Better suited to small/mid-size teams than large enterprise BI deployments$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Fewer prebuilt data connectors than large commercial BI platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Self-hosting requires basic technical setup and maintenance$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Is Chartbrew free?$q$, $q$Yes, the self-hosted open-source version is completely free. A cloud-hosted version starts at $24/month with a 14-day free trial.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Can I self-host Chartbrew?$q$, $q$Yes, Chartbrew can be self-hosted via Docker or deployed as a DigitalOcean Marketplace image.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$What data sources does Chartbrew support?$q$, $q$It connects to PostgreSQL, MySQL, and MongoDB databases, plus SaaS APIs like Stripe, Google Analytics, and Mailchimp, and generic REST endpoints.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Does Chartbrew have AI features?$q$, $q$Yes, it includes AI-assisted query suggestions and optimization for SQL and MongoDB queries.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Can Chartbrew dashboards be embedded on other websites?$q$, $q$Yes, individual charts or full dashboards can be embedded externally, commonly used for client-facing reporting.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Agency client reporting$q$, $q$Agencies build live, embeddable dashboards to share performance reports with clients without manual report generation.$q$, $q$Marketing and data agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Startup KPI tracking$q$, $q$Small product teams connect their database and SaaS tools directly to track business metrics without a dedicated analytics engineer.$q$, $q$Startups and small product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Self-hosted BI for developers$q$, $q$Developers who want full data control deploy Chartbrew on their own infrastructure as a lightweight BI alternative.$q$, $q$Developers and technical teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source software","Full dashboard and chart features","Deploy via Docker","Unlimited by your own infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$Cloud$q$, $q$From $24/month$q$, $q$monthly$q$, NULL, $q$["Managed hosting","14-day free trial","Additional integrations and storage","Team collaboration"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chartbrew is an open-source dashboard and reporting platform created by founder Răzvan Ilin, originating around 2018 and publicly launching out of beta in November 2020. It is available as a free, self-hostable open-source project on GitHub and as a paid cloud-hosted service.$q$, $q$The platform connects directly to databases and APIs to build live charts and dashboards without a separate BI or ETL layer, and it is particularly popular with agencies and small teams that need to deliver client-facing reporting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Chartbrew connects to PostgreSQL, MySQL, and MongoDB databases as well as SaaS APIs like Stripe, Google Analytics, and Mailchimp, and any generic REST endpoint. A point-and-click query builder or raw SQL editor lets users shape the underlying data, with AI-assisted query suggestions helping write and optimize SQL or MongoDB queries.$q$, $q$Dashboards combine charts, tables, and goal-tracking widgets, with scheduled refreshes, snapshot reports, and Slack/email/webhook alerts. Charts and full dashboards can be embedded externally, which is commonly used for client-facing reporting portals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted, open-source version of Chartbrew is completely free, deployable via Docker or as a DigitalOcean Marketplace image. The cloud-hosted version starts at $24/month with a 14-day free trial; free cloud usage is limited to core dashboard features, basic integrations, and up to 3 team members.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e940e3d2-e870-4b3e-819f-28d10c4d7db4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
