INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Single-query schema import$q$, $q$Retrieve a full database schema as JSON with one 'Smart Query,' with no credentials sent to ChartDB's servers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Instant ER diagram rendering$q$, $q$Automatically generate an interactive entity-relationship diagram from the imported schema.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Real-time collaboration$q$, $q$Invite teammates to view and edit diagrams together, with full undo/redo support.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Schema version history$q$, $q$Track schema changes over time with diffs to monitor how the database structure evolves.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$SQL export & cross-dialect migration$q$, $q$Export DDL scripts and use AI-driven conversion to migrate schemas between database dialects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$AI diagram generation$q$, $q$Generate a fully editable ER diagram from a natural-language description of a database.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Completely free and open-source with no installation required for basic use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Strong privacy model since database credentials never leave the user's machine$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Fast single-query schema import and instant diagram rendering$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$AI-assisted diagram generation and cross-dialect SQL export$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Young project (launched 2024) with a very small core team$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$No confirmed enterprise support tier or SLA$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Primarily community-supported rather than backed by dedicated customer success$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Advanced collaboration and version history features may be less mature than long-established paid tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Is ChartDB free?$q$, $q$Yes, ChartDB is free and open-source, usable directly at chartdb.io or self-hosted.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Does ChartDB store my database credentials?$q$, $q$No, ChartDB is designed so that database credentials never leave your machine; only the resulting schema JSON is used to build the diagram.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Who created ChartDB?$q$, $q$ChartDB was founded in August 2024 in Tel Aviv, Israel, by co-founders Jonathan Fishner and Guy Ben-Aharon.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Can ChartDB export SQL scripts?$q$, $q$Yes, ChartDB can export SQL DDL scripts, including AI-driven conversion between different database dialects.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Does ChartDB support real-time collaboration?$q$, $q$Yes, teammates can be invited to view and edit diagrams together in real time.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Understanding an unfamiliar database$q$, $q$Developers joining a new project use ChartDB to quickly visualize an existing database's schema and relationships.$q$, $q$Developers and engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Database migration planning$q$, $q$Teams use ChartDB's cross-dialect SQL export to plan and document migrations between database systems.$q$, $q$Database administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Schema documentation$q$, $q$Technical writers and architects use ChartDB to produce and maintain up-to-date ER diagrams for documentation.$q$, $q$Technical architects and documentation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$Open Source / Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Single-query schema import","Instant ER diagram rendering","Real-time collaboration","SQL export","AI diagram generation","No installation required"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ChartDB is a free, open-source database schema diagramming tool founded in August 2024 in Tel Aviv, Israel, by co-founders Jonathan Fishner and Guy Ben-Aharon. The two built and launched the project as an open-source MVP in under three weeks, reaching the front page of Hacker News within 72 hours and gaining thousands of GitHub stars shortly after launch.$q$, $q$The tool lets developers and database administrators instantly visualize a database's structure as an entity-relationship diagram by running a single query, without needing to install software or share database credentials with a third-party service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ChartDB's 'Smart Query' retrieves a database's schema as JSON in one step, which is rendered instantly as an interactive ER diagram — no credentials leave the user's machine. Teams can invite collaborators to view and edit diagrams in real time, with full undo/redo and schema version history that tracks diffs over time.$q$, $q$For migration and documentation, ChartDB exports SQL DDL scripts, including AI-driven cross-dialect conversion (for example, MySQL to PostgreSQL). An AI diagram generator can also build a fully editable ER diagram from a natural-language description of a database, useful for early-stage schema design.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1d81dd7e-c136-40e4-8989-d72a34c9daf3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ChartDB is free and open-source, usable directly at chartdb.io with no installation or account required for core diagramming, or self-hosted for teams that want to keep the tool inside their own environment. As of its founders' most recent public updates, the company remains fully bootstrapped with no confirmed enterprise pricing tier.$q$]::text[], 2);
