-- Enrichment marathon batch: Chamilo LMS, changedetection.io, Chanty, Chaport, Chargebee, CharlieHR, Chartbrew, ChartDB

-- ── Chamilo LMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chamilo LMS is a free, open-source learning management system for schools and enterprises, offering course authoring, assessments, virtual classrooms, and SCORM/xAPI support.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Spain$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$Chamilo LMS Review: Features, Pricing & Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Chamilo LMS is a free, open-source e-learning platform for schools and businesses. Explore its features, PRO pricing, and how it compares to Moodle.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chamilo LMS is a free, open-source learning management system (LMS) used for online and blended course delivery in schools, universities, and corporate training programs. Its codebase traces back to the Claroline project (started in 2000), which was forked into Dokeos in 2004 and forked again in 2010 to create Chamilo. The nonprofit Chamilo Association was legally registered in Belgium in June 2010 and has been headquartered in Spain since 2014; as of January 2026 the project is governed by BeezNest Belgium, the main commercial backer behind the software's development and enterprise services. Chamilo has been certified a Digital Public Good by the UN-backed Digital Public Goods Alliance (DPGA) and is reported to be used by more than 41 million learners worldwide across educational institutions, NGOs, government programs, and companies. The core software is released under a free, open-source license and can be self-hosted on any server at no licensing cost, which is its primary differentiator from proprietary LMS platforms like Moodle-adjacent commercial products or TalentLMS. Functionally, Chamilo covers the full instructional lifecycle: course authoring tools, configurable exams and complex assessment types, SCORM and xAPI (Tin Can) compliance for interoperable e-learning content, certificate generation, skills and competency tracking, and a course catalog with an integrated shopping cart for institutions that sell courses. It also includes social-learning features built directly into the platform, such as discussion forums, real-time chat, and wiki pages, plus integrated video conferencing for live virtual classrooms. More recent releases have added AI-assisted capabilities for content creation and automated grading, reflecting a broader trend among open-source LMS platforms to add generative AI tooling on top of a free core. Because Chamilo is self-hosted, organizations are responsible for their own server infrastructure, security patching, and technical maintenance unless they purchase support. For organizations that want to avoid managing this themselves, the Chamilo Association and its partners offer Chamilo PRO, an enterprise services package that bundles managed hosting, priority technical support, version upgrades and maintenance, custom development, third-party integrations, migration assistance (including from Moodle), and consulting; pricing for Chamilo PRO is not publicly listed and is quoted per organization based on scale and service level. This two-tier model — free core software plus paid enterprise services — is comparable to how other open-source projects like WordPress or Moodle monetize, rather than a traditional per-seat SaaS subscription. Chamilo is best suited for educational institutions, training providers, and mid-size to large organizations that have (or are willing to contract) the technical capacity to run and maintain a self-hosted platform, and that want to avoid recurring per-user SaaS fees at scale. It is less suited to non-technical individuals or very small teams wanting a fully managed, zero-setup solution, since even with Chamilo PRO the underlying software remains self-hosted rather than a pure multi-tenant SaaS product. Competitors most commonly cited against Chamilo include Moodle, Open edX, TalentLMS, and Docebo.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e674cd08-a074-41e5-a462-469391a5b739';

