-- ── changedetection.io ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$changedetection.io is an open-source website change monitoring tool that tracks price drops, restocks, and content changes, with a free self-hosted version and a paid cloud plan.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$changedetection.io Review: Features, Pricing & Setup$q$, seo_title),
  seo_meta_description = COALESCE($q$changedetection.io is a free, open-source tool for monitoring website changes, price drops, and restocks. See how it works, self-hosting steps, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$changedetection.io is an open-source website change detection and monitoring tool maintained by developer dgtlmoon on GitHub, distributed as a self-hosted application (via Docker, pip, or source) and also offered as a paid managed cloud service. The project's core purpose is to let users track specific web pages and get notified whenever the content changes — commonly used for detecting price drops on e-commerce sites, restock alerts on out-of-stock products, tracking edits to legal or policy documents, monitoring competitor websites, or catching unauthorized website defacement. Users add a URL to watch, and changedetection.io periodically fetches the page and compares it against the previous version, highlighting differences. Rather than monitoring an entire page indiscriminately, users can select specific elements on the page (via a visual point-and-click selector or CSS/XPath selectors) so only relevant content — such as a price field or a specific paragraph — triggers an alert, reducing noise from ads, timestamps, or other frequently changing but irrelevant page elements. For price and inventory tracking specifically, the tool has dedicated logic to detect numeric price changes (with configurable upper/lower bounds and percentage thresholds) and to alert when an out-of-stock product becomes available again. Beyond plain HTML pages, changedetection.io can track the filesize and checksum of PDF documents to catch updates to reports or legal filings without needing to download and diff them manually, and it supports advanced selectors including LXML-based regex functions (re:test, re:match) for parsing JSON API responses or deeply nested DOM structures. It also includes lightweight browser automation "steps" so a watch can log into a site, add an item to a cart, enter search terms, or click through a multi-step flow before capturing the content to monitor — useful for pages that sit behind interaction rather than being immediately visible on load. Notifications are handled through the Apprise notification library, giving changedetection.io out-of-the-box support for a wide range of destinations including Discord, Slack, Telegram, email, Microsoft Office 365, ntfy, Matrix, Rocket.Chat, and generic custom webhooks, so alerts can be routed into whatever tool a team already uses. The self-hosted version is completely free and open-source, requiring users to run the software on their own server or local machine (commonly via a Docker container), and it imposes no artificial limits on the number of watched URLs beyond what the host's own resources and the target sites' rate limits allow. For users who don't want to manage hosting, changedetection.io also offers a hosted SaaS plan starting at $8.99 per month, which supports tracking up to 5,000 URLs with a check frequency as fast as every 5 minutes, removing the need to run and maintain the checking infrastructure. The tool is popular among developers, deal hunters, researchers, and small businesses that need lightweight, flexible change monitoring without committing to more expensive commercial web-scraping or monitoring platforms, and it is frequently cited as a leading self-hosted alternative to commercial products like Visualping or Distill.io.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ac4cf7c0-028b-4c2e-ba11-afcc0b9a7533';

