-- ── CharlieHR ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CharlieHR is a UK-built HR platform for small businesses, covering onboarding, absence management, and employee records, with optional recruitment and HR advice add-ons.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$£20/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$~40 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CharlieHR Review 2026: Pricing, Features & Add-Ons$q$, seo_title),
  seo_meta_description = COALESCE($q$CharlieHR is a UK small-business HR platform for onboarding and absence tracking. Compare Core, Recruit, and Advice pricing plus key features for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CharlieHR is an HR software platform built specifically for small businesses, founded in London in 2015 (with the founding team describing operations starting from a small Whitechapel office in 2016) by co-founders including Rob O'Donovan and Ben Gateley. The company remains headquartered in London, now working with a distributed team of around 40 people across the UK, and is registered with UK Companies House as Charlie HR Ltd. The platform's core focus is replacing spreadsheets and manual admin for small-company HR teams: it centralizes employee records in a GDPR-compliant system, automates onboarding workflows for new hires, and manages absence and time-off requests with configurable leave types, manager approval flows, and real-time calendar views that sync with Google Calendar or Outlook. Employees can self-serve by requesting time off directly in the platform and viewing their own allowance usage, while managers can approve requests with one click, reducing the back-and-forth typically handled over email or spreadsheets. CharlieHR also includes automated reminders for HR-related deadlines and document storage designed to keep sensitive employee data compliant with UK/EU data protection requirements. Beyond the core HR module, CharlieHR offers two paid add-ons that require an active Core subscription and cannot be purchased standalone: Charlie Recruit, an applicant tracking system that lets small teams manage hiring pipelines without adopting separate recruitment software, and Charlie Advice, a 1-to-1 HR advisory service for businesses that want expert guidance on employment law and HR decisions rather than relying solely on self-service software. Pricing is structured by company headcount rather than a flat per-user rate: the Core HR plan starts at £20 per month for businesses with 1–4 employees and scales up to £735 per month for organizations with 250 or more employees, with new customers in the 1–4 employee band getting a 75% introductory discount for their first six months (bringing the effective starting price to roughly £5/month). The Recruit add-on starts from £55 per month and the Advice add-on starts from £179 per month, both on top of an active Core subscription; all listed prices exclude UK VAT. CharlieHR offers a 7-day free trial for prospective customers to evaluate the platform before committing. The product is primarily aimed at UK-based small businesses and startups — companies too small to justify a dedicated HR team or an enterprise HRIS platform like Workday or BambooHR, but that have outgrown tracking holidays and onboarding checklists manually. Because pricing and much of the compliance framing is UK-specific (GDPR, UK employment law guidance through Advice), CharlieHR is less commonly positioned for companies operating primarily outside the UK, and it does not include full payroll processing, which distinguishes it from all-in-one HR and payroll platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '28db2214-8104-44f7-8d16-5482ac920f21';

