-- ── Chartbrew ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chartbrew is an open-source platform for building live dashboards and reports from databases and APIs, with an AI assistant, scheduling, and embeddable charts.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chartbrew Review: Open-Source Dashboards & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Chartbrew is an open-source dashboard and reporting tool for databases and APIs. See self-hosted and cloud pricing plus key features for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chartbrew is an open-source reporting and dashboard platform created by founder Răzvan Ilin, who built the initial version to monitor stats for his own digital products before turning it into a standalone product; the project traces to around 2018 and came out of beta in November 2020 under the trading entity Depomo Ltd. It is available as a free, self-hostable open-source application on GitHub as well as a paid cloud-hosted version at app.chartbrew.com. The platform's core function is connecting directly to data sources — relational and NoSQL databases (PostgreSQL, MySQL, MongoDB) as well as SaaS APIs and generic REST endpoints (including Stripe, Google Analytics, and Mailchimp) — and turning that data into charts, tables, and dashboards without requiring a separate BI or ETL layer. Users build queries either through a point-and-click query builder (selecting data sources, fields, and filters visually) or by writing raw SQL directly against connected databases, and Chartbrew includes AI-assisted query suggestions and optimization to help users write and refine SQL or MongoDB queries within the dashboard editor. Dashboards combine charts, tables, and goal-tracking widgets so teams can monitor business or product metrics at a glance, and they can be scheduled to refresh automatically, send periodic snapshot reports, or trigger alerts through Slack, email, or webhooks when metrics cross defined thresholds. Charts and full dashboards can be embedded in external websites or client-facing portals, which has made Chartbrew particularly popular with agencies that need to deliver live, branded reporting dashboards to their own clients rather than sending static reports. Pricing follows a freemium, open-core model. The self-hosted version is completely free and open-source, with users responsible for their own infrastructure (Chartbrew is commonly deployed via Docker and is also available as a DigitalOcean Marketplace image). The cloud-hosted version starts at $24 per month and includes a 14-day free trial; free-tier cloud usage is limited to core dashboard features, basic integrations, and up to 3 team members, with paid tiers unlocking more data source integrations, storage, and automation. Chartbrew is positioned as an open-source alternative to commercial BI platforms like Power BI, Tableau, and Databox, but scoped for smaller teams: it is best suited to agencies building client reporting dashboards, startups and small product teams tracking KPIs without a dedicated data/analytics engineer, and developers who want a lightweight, self-hostable BI tool that connects directly to their existing databases and SaaS APIs rather than requiring a data warehouse. It is less suited to large enterprises needing complex governance, row-level security, or massive-scale data modeling, where dedicated enterprise BI platforms remain more appropriate.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e940e3d2-e870-4b3e-819f-28d10c4d7db4';

