-- ── ChartDB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ChartDB is a free, open-source, web-based tool that instantly visualizes database schemas as interactive ER diagrams using a single query, with no credentials leaving your machine.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE($q$2 co-founders (bootstrapped)$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ChartDB Review: Free Database Diagram Tool & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$ChartDB is a free, open-source tool that turns a single database query into an interactive ER diagram. See how it works, key features, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ChartDB is a free, open-source database schema visualization tool founded in August 2024 in Tel Aviv, Israel, by co-founders Jonathan Fishner (CEO), a software engineer with a background in data platforms who previously worked at Fiverr, and Guy Ben-Aharon (CTO), a full-stack engineer with UX experience who previously worked at Wix. The two built and launched ChartDB as an open-source MVP in under three weeks after repeatedly experiencing the same frustration on different projects: understanding an existing database's schema was slow and tedious with available tools. The launch was unusually successful for a new open-source project — it reached the front page of Hacker News within 72 hours and had accumulated more than 3,000 GitHub stars and over 20 contributors within about a month, and the company has remained fully bootstrapped with no outside funding as of mid-2025, while reporting early revenue traction. ChartDB's core mechanic is a single 'Smart Query': users run one query against their database (via chartdb.io or a self-hosted instance) that retrieves the schema as JSON, which ChartDB then renders instantly as an interactive entity-relationship (ER) diagram in the browser. Critically, the tool is designed so that no database credentials or connection strings are ever sent to ChartDB's servers — only the resulting schema JSON is used to build the diagram, which the company positions as a security and privacy advantage over tools that require direct database connections. Once a schema is imported, users can edit the diagram directly: creating, renaming, and connecting tables and relationships, with full undo/redo support, and inviting teammates to view and edit diagrams together in real time for collaborative schema design or documentation work. ChartDB also tracks schema changes over time, showing diffs and version history so teams can monitor how a database's structure evolves. For migration and documentation use cases, ChartDB can export SQL DDL scripts, including AI-driven cross-dialect export that can translate a schema from one database system to another (for example, generating PostgreSQL-compatible DDL from a MySQL schema, or migrating between SQLite and MariaDB). An AI diagram generator can also turn a natural-language description of a database into a fully editable, optimized ER diagram from scratch, useful for early-stage schema design before any actual database exists. ChartDB can be used directly at chartdb.io with no installation or account required for basic diagramming, or self-hosted for teams that want to keep all diagramming infrastructure inside their own environment. As an open-source project with no confirmed paid enterprise tier as of its research, ChartDB is positioned as a free alternative to commercial database diagramming and modeling tools like SqlDBM, aimed at developers, database administrators, and engineering teams who need to quickly understand, document, or migrate a database schema without a lengthy setup process.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1d81dd7e-c136-40e4-8989-d72a34c9daf3';

